# INSIGHT: sorted + two pointers → O(n) O(1) space
left, right = 0, len(numbers) - 1
while left < right:
    s = numbers[left] + numbers[right]
    if s == target:
        return [left + 1, right + 1]  # 1-indexed
    elif s > target:
        right -= 1
    else:
        left += 1
# Time: O(n)  Space: O(1)
